from dataclasses import dataclass, field
from typing import Literal

RiskDomain = Literal[
    "GENERAL", "FINANCIAL_ADVICE", "MEDICAL_ADVICE",
    "LEGAL_ADVICE", "SAFETY_CRITICAL", "EMPLOYMENT_DECISION"
]

HumanReviewLevel = Literal["NONE", "OPTIONAL", "MANDATORY", "MANDATORY_LICENSED_PROFESSIONAL"]

@dataclass
class AIFeatureDesign:
    feature_name: str
    risk_domain: RiskDomain
    output_type: str                        # "recommendation", "content", "decision", "analysis"
    user_sees_ai_source: bool               # disclosed as AI-generated
    human_review_level: HumanReviewLevel
    review_reviewer_role: str               # e.g. "licensed physician", "qualified advisor", "any employee"
    disclaimer_shown: bool
    disclaimer_text: str
    audit_log_kept: bool

    def minimum_human_review_required(self) -> HumanReviewLevel:
        high_risk = {"FINANCIAL_ADVICE", "MEDICAL_ADVICE", "LEGAL_ADVICE",
                     "SAFETY_CRITICAL", "EMPLOYMENT_DECISION"}
        if self.risk_domain in high_risk:
            return "MANDATORY_LICENSED_PROFESSIONAL"
        return "OPTIONAL"

    def liability_gaps(self) -> list[str]:
        gaps = []
        required = self.minimum_human_review_required()
        review_order = ["NONE", "OPTIONAL", "MANDATORY", "MANDATORY_LICENSED_PROFESSIONAL"]
        if review_order.index(self.human_review_level) < review_order.index(required):
            gaps.append(
                f"Human review level ({self.human_review_level}) is below minimum required "
                f"({required}) for {self.risk_domain}"
            )
        if not self.user_sees_ai_source:
            gaps.append("Users are not informed that output is AI-generated — may violate disclosure requirements")
        if not self.audit_log_kept:
            gaps.append("No audit log — cannot reconstruct the AI output if a claim arises")
        if not self.disclaimer_shown and self.risk_domain != "GENERAL":
            gaps.append("No disclaimer shown — users may over-rely on AI output")
        return gaps

    def is_deployment_ready(self) -> bool:
        return len(self.liability_gaps()) == 0

    def design_summary(self) -> str:
        status = "READY" if self.is_deployment_ready() else f"GAPS: {len(self.liability_gaps())}"
        return (
            f"{self.feature_name} [{self.risk_domain}]: "
            f"Review={self.human_review_level} | "
            f"Disclosed={self.user_sees_ai_source} | "
            f"Audit={self.audit_log_kept} | "
            f"Status={status}"
        )
